from __future__ import annotations

import re
import shutil
from datetime import datetime
from pathlib import Path

TARGET = Path.home() / 'lndk-pay' / 'app' / 'backend' / 'app.py'


def backup_file(path: Path) -> Path:
    ts = datetime.now().strftime('%Y%m%d-%H%M%S')
    dst = path.with_suffix(path.suffix + f'.bak-{ts}')
    shutil.copy2(path, dst)
    return dst


def replace_once(text: str, old: str, new: str, label: str) -> str:
    if old not in text:
        raise SystemExit(f'Patch failed: could not find block for {label}')
    return text.replace(old, new, 1)


def main() -> None:
    if not TARGET.exists():
        raise SystemExit(f'Not found: {TARGET}')

    backup = backup_file(TARGET)
    text = TARGET.read_text(encoding='utf-8')

    marker = 'NOSTR_NAME_MAP = _load_nostr_name_map()\n\napp = FastAPI(title="LNDK Backend", version="0.5.0")\n'
    insert = '''NOSTR_NAME_MAP = _load_nostr_name_map()\n\n\nclass IdentityConfigPayload(BaseModel):\n    alias: str = Field(min_length=1, max_length=64)\n    nostr_pubkey: str = Field(min_length=8, max_length=200)\n    relays: Optional[list[str]] = None\n    nip05_enabled: bool = True\n    zap_enabled: bool = True\n\n\ndef _get_identity_store() -> dict[str, Any]:\n    cfg = load_config()\n    store = cfg.get("nostr_identities", {}) or {}\n    return store if isinstance(store, dict) else {}\n\n\ndef _save_identity_store(store: dict[str, Any]) -> None:\n    cfg = load_config()\n    cfg["nostr_identities"] = store\n    save_config(cfg)\n\n\ndef _normalize_identity_alias(alias: str) -> str:\n    return _normalize_lnurl_username(alias)\n\n\ndef _normalize_nostr_pubkey_input(value: str) -> str:\n    raw = (value or "").strip()\n    if not raw:\n        raise HTTPException(status_code=400, detail="nostr_pubkey required")\n\n    if re.fullmatch(r"[0-9a-fA-F]{64}", raw):\n        return raw.lower()\n\n    decoded = _npub_to_hex_pubkey(raw)\n    if decoded and re.fullmatch(r"[0-9a-f]{64}", decoded):\n        return decoded.lower()\n\n    raise HTTPException(status_code=400, detail="Invalid nostr pubkey. Expected 64-char hex or npub1...")\n\n\ndef _get_identity_config(alias: str) -> dict[str, Any]:\n    alias = (alias or "").strip().lower()\n    if not alias:\n        return {}\n\n    item = _get_identity_store().get(alias) or {}\n    if not isinstance(item, dict):\n        return {}\n\n    return {\n        "alias": alias,\n        "nostr_pubkey": str(item.get("nostr_pubkey", "")).strip().lower(),\n        "relays": [str(x).strip() for x in (item.get("relays") or []) if str(x).strip()],\n        "nip05_enabled": bool(item.get("nip05_enabled", True)),\n        "zap_enabled": bool(item.get("zap_enabled", True)),\n    }\n\n\ndef _set_identity_config(*, alias: str, nostr_pubkey: str, relays: Optional[list[str]] = None, nip05_enabled: bool = True, zap_enabled: bool = True) -> dict[str, Any]:\n    alias = _normalize_identity_alias(alias)\n    pubkey_hex = _normalize_nostr_pubkey_input(nostr_pubkey)\n    cleaned_relays = [str(x).strip() for x in (relays or []) if str(x).strip()]\n\n    store = _get_identity_store()\n    store[alias] = {\n        "nostr_pubkey": pubkey_hex,\n        "relays": cleaned_relays,\n        "nip05_enabled": bool(nip05_enabled),\n        "zap_enabled": bool(zap_enabled),\n    }\n    _save_identity_store(store)\n    return _get_identity_config(alias)\n\n\ndef _lookup_env_nostr_pubkey_hex(name: str) -> str:\n    if not name:\n        return ""\n    raw = str(NOSTR_NAME_MAP.get(name.strip().lower(), "")).strip()\n    if not raw:\n        return ""\n    if re.fullmatch(r"[0-9a-fA-F]{64}", raw):\n        return raw.lower()\n    return _npub_to_hex_pubkey(raw) or ""\n\n\ndef _get_nostr_pubkey_hex_for_name(name: str) -> str:\n    cfg = _get_identity_config(name)\n    if cfg.get("nostr_pubkey"):\n        return cfg["nostr_pubkey"]\n    return _lookup_env_nostr_pubkey_hex(name)\n\n\ndef _is_nip05_active_for_name(name: str) -> bool:\n    cfg = _get_identity_config(name)\n    if cfg:\n        return bool(cfg.get("nip05_enabled") and cfg.get("nostr_pubkey"))\n    return bool(_lookup_env_nostr_pubkey_hex(name))\n\n\ndef _is_zap_active_for_name(name: str) -> bool:\n    cfg = _get_identity_config(name)\n    if cfg:\n        return bool(cfg.get("zap_enabled") and cfg.get("nostr_pubkey"))\n    return bool(_lookup_env_nostr_pubkey_hex(name))\n\n\ndef _get_nostr_relays_for_name(name: str) -> list[str]:\n    cfg = _get_identity_config(name)\n    relays = cfg.get("relays") or []\n    return [str(x).strip() for x in relays if str(x).strip()]\n\n\napp = FastAPI(title="LNDK Backend", version="0.5.0")\n'''
    text = replace_once(text, marker, insert, 'identity helper insertion')

    lnurl_meta_old = '''@app.get("/.well-known/lnurlp/{username}", response_model=LnurlPayMetadataResponse)\ndef lnurl_pay_metadata(username: str) -> LnurlPayMetadataResponse:\n    alias = _resolve_lnurl_alias(username)\n\n    min_sendable = LNURL_MIN_SENDABLE_MSAT\n    max_sendable = LNURL_MAX_SENDABLE_MSAT\n\n    if alias["fixed_amount_sat"] is not None:\n        fixed_msat = int(alias["fixed_amount_sat"]) * 1000\n        min_sendable = fixed_msat\n        max_sendable = fixed_msat\n\n    return LnurlPayMetadataResponse(\n        callback=_lnurl_callback_url(alias["username"]),\n        minSendable=min_sendable,\n        maxSendable=max_sendable,\n        metadata=_lnurl_metadata_json(alias["identifier"], alias["description"]),\n        commentAllowed=max(0, LNURL_COMMENT_ALLOWED),\n        allowsNostr=True,\n        nostrPubkey=_get_nostr_pubkey_hex_for_name(alias["username"]),\n    )\n\n\n'''
    lnurl_meta_new = '''@app.get("/.well-known/lnurlp/{username}", response_model=LnurlPayMetadataResponse)\ndef lnurl_pay_metadata(username: str) -> LnurlPayMetadataResponse:\n    alias = _resolve_lnurl_alias(username)\n\n    min_sendable = LNURL_MIN_SENDABLE_MSAT\n    max_sendable = LNURL_MAX_SENDABLE_MSAT\n\n    if alias["fixed_amount_sat"] is not None:\n        fixed_msat = int(alias["fixed_amount_sat"]) * 1000\n        min_sendable = fixed_msat\n        max_sendable = fixed_msat\n\n    nostr_pubkey = _get_nostr_pubkey_hex_for_name(alias["username"])\n    zap_enabled = _is_zap_active_for_name(alias["username"])\n\n    return LnurlPayMetadataResponse(\n        callback=_lnurl_callback_url(alias["username"]),\n        minSendable=min_sendable,\n        maxSendable=max_sendable,\n        metadata=_lnurl_metadata_json(alias["identifier"], alias["description"]),\n        commentAllowed=max(0, LNURL_COMMENT_ALLOWED),\n        allowsNostr=bool(zap_enabled and nostr_pubkey),\n        nostrPubkey=nostr_pubkey if zap_enabled else "",\n    )\n\n\n'''
    text = replace_once(text, lnurl_meta_old, lnurl_meta_new, 'lnurl metadata route')

    lnurl_cb_old = '''@app.get("/api/lnurl/callback/{username}")\nasync def lnurl_callback(\n    username: str,\n    amount: int = Query(..., ge=1, description="Requested amount in millisatoshis"),\n    comment: Optional[str] = Query(default=None),\n    nostr: Optional[str] = Query(default=None),\n    lnurl: Optional[str] = Query(default=None),\n) -> dict[str, Any]:\n    alias = _resolve_lnurl_alias(username)\n\n    min_sendable = LNURL_MIN_SENDABLE_MSAT\n    max_sendable = LNURL_MAX_SENDABLE_MSAT\n\n    if alias["fixed_amount_sat"] is not None:\n        fixed_msat = int(alias["fixed_amount_sat"]) * 1000\n        min_sendable = fixed_msat\n        max_sendable = fixed_msat\n\n    if amount < min_sendable or amount > max_sendable:\n        raise HTTPException(status_code=400, detail="amount outside configured LNURL min/max range")\n\n    if comment and len(comment) > max(0, LNURL_COMMENT_ALLOWED):\n        raise HTTPException(status_code=400, detail="comment too long")\n\n    print(f"LNURL callback username={username} amount={amount} comment={comment!r}")\n    amount_sat = max(1, math.ceil(amount / 1000))\n\n    metadata = _lnurl_metadata_for_alias(alias)\n    description_hash = hashlib.sha256(metadata.encode("utf-8")).digest()\n    description_hash_b64 = base64.b64encode(description_hash).decode("ascii")\n\n    memo = comment.strip() if comment else ""\n    zap_request_event = None\n    recipient_nostr_hex = _get_nostr_pubkey_hex_for_name(username)\n\n    if nostr:\n        zap_request_event = _parse_zap_request(\n            nostr_raw=nostr,\n            expected_pubkey_hex=recipient_nostr_hex,\n            amount_msat=amount,\n        )\n        description_hash_b64 = _sha256_b64(nostr.encode("utf-8"))\n        memo = ""\n\n    invoice = await _create_bolt11_invoice(\n        amount_sat=amount_sat,\n        memo=memo,\n        description_hash=description_hash_b64,\n    )\n\n    payment_request = invoice["payment_request"] if isinstance(invoice, dict) else str(invoice)\n\n    success_message = f"Payment request for {alias['identifier']}"\n    if comment:\n        success_message = f"{success_message} • Comment: {comment}"\n    if zap_request_event:\n        success_message = f"Zap invoice for {alias['identifier']}"\n\n    return {\n        "pr": payment_request,\n        "routes": [],\n        "successAction": {\n            "tag": "message",\n            "message": success_message,\n        },\n        "disposable": False,\n        "allowsNostr": True,\n        "nostrPubkey": _get_nostr_pubkey_hex_for_name(username),\n    }\n\n\n'''
    lnurl_cb_new = '''@app.get("/api/lnurl/callback/{username}")\nasync def lnurl_callback(\n    username: str,\n    amount: int = Query(..., ge=1, description="Requested amount in millisatoshis"),\n    comment: Optional[str] = Query(default=None),\n    nostr: Optional[str] = Query(default=None),\n    lnurl: Optional[str] = Query(default=None),\n) -> dict[str, Any]:\n    alias = _resolve_lnurl_alias(username)\n\n    min_sendable = LNURL_MIN_SENDABLE_MSAT\n    max_sendable = LNURL_MAX_SENDABLE_MSAT\n\n    if alias["fixed_amount_sat"] is not None:\n        fixed_msat = int(alias["fixed_amount_sat"]) * 1000\n        min_sendable = fixed_msat\n        max_sendable = fixed_msat\n\n    if amount < min_sendable or amount > max_sendable:\n        raise HTTPException(status_code=400, detail="amount outside configured LNURL min/max range")\n\n    if comment and len(comment) > max(0, LNURL_COMMENT_ALLOWED):\n        raise HTTPException(status_code=400, detail="comment too long")\n\n    print(f"LNURL callback username={username} amount={amount} comment={comment!r}")\n    amount_sat = max(1, math.ceil(amount / 1000))\n\n    metadata = _lnurl_metadata_for_alias(alias)\n    description_hash = hashlib.sha256(metadata.encode("utf-8")).digest()\n    description_hash_b64 = base64.b64encode(description_hash).decode("ascii")\n\n    memo = comment.strip() if comment else ""\n    zap_request_event = None\n    recipient_nostr_hex = _get_nostr_pubkey_hex_for_name(username)\n    zap_enabled = _is_zap_active_for_name(username)\n\n    if nostr:\n        if not (zap_enabled and recipient_nostr_hex):\n            raise HTTPException(status_code=400, detail="Zaps are not enabled for this lightning address")\n        zap_request_event = _parse_zap_request(\n            nostr_raw=nostr,\n            expected_pubkey_hex=recipient_nostr_hex,\n            amount_msat=amount,\n        )\n        description_hash_b64 = _sha256_b64(nostr.encode("utf-8"))\n        memo = ""\n\n    invoice = await _create_bolt11_invoice(\n        amount_sat=amount_sat,\n        memo=memo,\n        description_hash=description_hash_b64,\n    )\n\n    payment_request = invoice["payment_request"] if isinstance(invoice, dict) else str(invoice)\n\n    success_message = f"Payment request for {alias['identifier']}"\n    if comment:\n        success_message = f"{success_message} • Comment: {comment}"\n    if zap_request_event:\n        success_message = f"Zap invoice for {alias['identifier']}"\n\n    return {\n        "pr": payment_request,\n        "routes": [],\n        "successAction": {\n            "tag": "message",\n            "message": success_message,\n        },\n        "disposable": False,\n        "allowsNostr": bool(zap_enabled and recipient_nostr_hex),\n        "nostrPubkey": recipient_nostr_hex if zap_enabled else "",\n    }\n\n\n'''
    text = replace_once(text, lnurl_cb_old, lnurl_cb_new, 'lnurl callback route')

    preview_old = '''@app.post("/api/preview-pay-target")\nasync def preview_pay_target(payload: PreviewPayTargetRequest):\n    target = payload.target.strip()\n    if not target:\n        raise HTTPException(status_code=400, detail="target required")\n\n    lowered = target.lower()\n\n    if lowered.startswith("lnbc") or lowered.startswith("lntb") or lowered.startswith("lnbcrt"):\n        macaroon_hex = _read_macaroon_hex(LND_MACAROON_PATH)\n        headers = {"Grpc-Metadata-macaroon": macaroon_hex}\n        verify = False if LND_REST_INSECURE else LND_TLS_CERT_PATH\n\n        try:\n            async with httpx.AsyncClient(timeout=LND_REST_TIMEOUT, verify=verify) as client:\n                response = await client.get(f"{LND_REST_URL}/v1/payreq/{target}", headers=headers)\n        except Exception as exc:\n            raise HTTPException(status_code=502, detail=f"LND REST decodepayreq failed: {exc}") from exc\n\n        try:\n            data = response.json()\n        except Exception:\n            raise HTTPException(status_code=502, detail="LND REST decodepayreq returned invalid JSON")\n\n        if response.status_code >= 400:\n            raise HTTPException(status_code=502, detail=f"LND REST decodepayreq error: {data}")\n\n        return {\n            "kind": "bolt11",\n            "title": "BOLT11 Invoice",\n            "amount_sat": data.get("num_satoshis") or data.get("numSatoshis") or "",\n            "description": data.get("description") or "",\n            "destination": data.get("destination") or "",\n            "image_data_url": "",\n            "comment_allowed": 0,\n            "min_sat": "",\n            "max_sat": "",\n        }\n\n    if "@" in target and " " not in target:\n        lnurlp_url = _lightning_address_to_lnurlp_url(target)\n        meta = await _fetch_lnurl_metadata_from_url(lnurlp_url)\n        meta_info = _extract_lnurl_metadata_info(meta.get("metadata"))\n\n        return {\n            "kind": "lightning_address",\n            "title": "Lightning Address",\n            "identifier": target,\n            "description": meta_info["text_plain"] or meta.get("description", ""),\n            "image_data_url": meta_info["image_data_url"],\n            "comment_allowed": int(meta.get("commentAllowed") or 0),\n            "min_sat": int(meta.get("minSendable") or 0) // 1000,\n            "max_sat": int(meta.get("maxSendable") or 0) // 1000,\n            "raw": meta,\n        }\n\n    if lowered.startswith("lnurl1"):\n        url = _decode_lnurl_bech32(target)\n        meta = await _fetch_lnurl_metadata_from_url(url)\n        meta_info = _extract_lnurl_metadata_info(meta.get("metadata"))\n\n        return {\n            "kind": "lnurl",\n            "title": "LNURL Pay",\n            "identifier": target,\n            "description": meta_info["text_plain"] or meta.get("description", ""),\n            "image_data_url": meta_info["image_data_url"],\n            "comment_allowed": int(meta.get("commentAllowed") or 0),\n            "min_sat": int(meta.get("minSendable") or 0) // 1000,\n            "max_sat": int(meta.get("maxSendable") or 0) // 1000,\n            "raw": meta,\n        }\n\n    return {\n        "kind": "unknown",\n        "title": "",\n        "description": "",\n        "image_data_url": "",\n        "comment_allowed": 0,\n        "min_sat": "",\n        "max_sat": "",\n    }\n\n\n'''
    preview_new = '''@app.post("/api/preview-pay-target")\nasync def preview_pay_target(payload: PreviewPayTargetRequest):\n    target = payload.target.strip()\n    if not target:\n        raise HTTPException(status_code=400, detail="target required")\n\n    lowered = target.lower()\n\n    if lowered.startswith("lnbc") or lowered.startswith("lntb") or lowered.startswith("lnbcrt"):\n        macaroon_hex = _read_macaroon_hex(LND_MACAROON_PATH)\n        headers = {"Grpc-Metadata-macaroon": macaroon_hex}\n        verify = False if LND_REST_INSECURE else LND_TLS_CERT_PATH\n\n        try:\n            async with httpx.AsyncClient(timeout=LND_REST_TIMEOUT, verify=verify) as client:\n                response = await client.get(f"{LND_REST_URL}/v1/payreq/{target}", headers=headers)\n        except Exception as exc:\n            raise HTTPException(status_code=502, detail=f"LND REST decodepayreq failed: {exc}") from exc\n\n        try:\n            data = response.json()\n        except Exception:\n            raise HTTPException(status_code=502, detail="LND REST decodepayreq returned invalid JSON")\n\n        if response.status_code >= 400:\n            raise HTTPException(status_code=502, detail=f"LND REST decodepayreq error: {data}")\n\n        return {\n            "kind": "bolt11",\n            "title": "BOLT11 Invoice",\n            "amount_sat": data.get("num_satoshis") or data.get("numSatoshis") or "",\n            "description": data.get("description") or "",\n            "destination": data.get("destination") or "",\n            "image_data_url": "",\n            "comment_allowed": 0,\n            "min_sat": "",\n            "max_sat": "",\n            "allows_nostr": False,\n            "nip05_active": False,\n            "nostr_pubkey": "",\n        }\n\n    if "@" in target and " " not in target:\n        lnurlp_url = _lightning_address_to_lnurlp_url(target)\n        meta = await _fetch_lnurl_metadata_from_url(lnurlp_url)\n        meta_info = _extract_lnurl_metadata_info(meta.get("metadata"))\n\n        username = target.split("@", 1)[0].strip().lower()\n        nostr_pubkey = _get_nostr_pubkey_hex_for_name(username)\n\n        return {\n            "kind": "lightning_address",\n            "title": "Lightning Address",\n            "identifier": target,\n            "description": meta_info["text_plain"] or meta.get("description", ""),\n            "image_data_url": meta_info["image_data_url"],\n            "comment_allowed": int(meta.get("commentAllowed") or 0),\n            "min_sat": int(meta.get("minSendable") or 0) // 1000,\n            "max_sat": int(meta.get("maxSendable") or 0) // 1000,\n            "allows_nostr": bool(meta.get("allowsNostr") and nostr_pubkey and _is_zap_active_for_name(username)),\n            "nip05_active": _is_nip05_active_for_name(username),\n            "nostr_pubkey": nostr_pubkey,\n            "raw": meta,\n        }\n\n    if lowered.startswith("lnurl1"):\n        url = _decode_lnurl_bech32(target)\n        meta = await _fetch_lnurl_metadata_from_url(url)\n        meta_info = _extract_lnurl_metadata_info(meta.get("metadata"))\n\n        return {\n            "kind": "lnurl",\n            "title": "LNURL Pay",\n            "identifier": target,\n            "description": meta_info["text_plain"] or meta.get("description", ""),\n            "image_data_url": meta_info["image_data_url"],\n            "comment_allowed": int(meta.get("commentAllowed") or 0),\n            "min_sat": int(meta.get("minSendable") or 0) // 1000,\n            "max_sat": int(meta.get("maxSendable") or 0) // 1000,\n            "allows_nostr": bool(meta.get("allowsNostr")),\n            "nip05_active": False,\n            "nostr_pubkey": str(meta.get("nostrPubkey") or ""),\n            "raw": meta,\n        }\n\n    return {\n        "kind": "unknown",\n        "title": "",\n        "description": "",\n        "image_data_url": "",\n        "comment_allowed": 0,\n        "min_sat": "",\n        "max_sat": "",\n        "allows_nostr": False,\n        "nip05_active": False,\n        "nostr_pubkey": "",\n    }\n\n\n'''
    text = replace_once(text, preview_old, preview_new, 'preview-pay-target route')

    nostr_old = '''@app.get("/.well-known/nostr.json")\nasync def nostr_well_known(name: str = Query(default=None)):\n    if name:\n        key = name.strip().lower()\n        pubkey = NOSTR_NAME_MAP.get(key)\n        if not pubkey:\n            return JSONResponse({"names": {}}, status_code=200)\n\n        pubkey_hex = _npub_to_hex_pubkey(pubkey)\n        if not pubkey_hex:\n            return JSONResponse({"names": {}}, status_code=200)\n\n        return {"names": {key: pubkey_hex}}\n\n    result = {}\n    for key, pubkey in NOSTR_NAME_MAP.items():\n        pubkey_hex = _npub_to_hex_pubkey(pubkey)\n        if pubkey_hex:\n            result[key] = pubkey_hex\n\n    return {"names": result}\n'''
    nostr_new = '''@app.get("/api/identity-config")\nasync def get_identity_config_api(alias: str = Query(..., min_length=1)):\n    key = _normalize_identity_alias(alias)\n    cfg = _get_identity_config(key)\n    if cfg:\n        return {**cfg, "exists": True}\n\n    fallback_pubkey = _lookup_env_nostr_pubkey_hex(key)\n    return {\n        "alias": key,\n        "nostr_pubkey": fallback_pubkey,\n        "relays": [],\n        "nip05_enabled": bool(fallback_pubkey),\n        "zap_enabled": bool(fallback_pubkey),\n        "exists": bool(fallback_pubkey),\n        "source": "env" if fallback_pubkey else "none",\n    }\n\n\n@app.post("/api/identity-config")\nasync def save_identity_config_api(payload: IdentityConfigPayload):\n    saved = _set_identity_config(\n        alias=payload.alias,\n        nostr_pubkey=payload.nostr_pubkey,\n        relays=payload.relays or [],\n        nip05_enabled=payload.nip05_enabled,\n        zap_enabled=payload.zap_enabled,\n    )\n    return {**saved, "saved": True}\n\n\n@app.get("/.well-known/nostr.json")\nasync def nostr_well_known(name: str = Query(default=None)):\n    names: dict[str, str] = {}\n    relays: dict[str, list[str]] = {}\n\n    for key, raw_pubkey in NOSTR_NAME_MAP.items():\n        pubkey_hex = _lookup_env_nostr_pubkey_hex(key)\n        if pubkey_hex:\n            names[key] = pubkey_hex\n\n    for key, item in _get_identity_store().items():\n        if not isinstance(item, dict):\n            continue\n        if not item.get("nip05_enabled", True):\n            continue\n\n        pubkey_hex = str(item.get("nostr_pubkey", "")).strip().lower()\n        if not re.fullmatch(r"[0-9a-f]{64}", pubkey_hex):\n            continue\n\n        names[key] = pubkey_hex\n\n        relay_list = [str(x).strip() for x in (item.get("relays") or []) if str(x).strip()]\n        if relay_list:\n            relays[pubkey_hex] = relay_list\n\n    if name:\n        key = name.strip().lower()\n        pubkey_hex = names.get(key, "")\n        if not pubkey_hex:\n            return JSONResponse({"names": {}}, status_code=200)\n\n        result = {"names": {key: pubkey_hex}}\n        if pubkey_hex in relays:\n            result["relays"] = {pubkey_hex: relays[pubkey_hex]}\n        return result\n\n    result = {"names": names}\n    if relays:\n        result["relays"] = relays\n    return result\n'''
    text = replace_once(text, nostr_old, nostr_new, 'nostr well-known route')

    TARGET.write_text(text, encoding='utf-8')
    print(f'Patched: {TARGET}')
    print(f'Backup : {backup}')


if __name__ == '__main__':
    main()
